#include <stdio.h>
#include <stdlib.h>
int main(void) {
    int N;
    if (scanf("%d", &N) != 1) return 0;
    long long a00 = 0;
    long long *topRow = (long long*)malloc(sizeof(long long) * (size_t)N);
    long long *leftCol = (long long*)malloc(sizeof(long long) * (size_t)N);
    if (!topRow || !leftCol) return 0;
    for (int j = 0; j < N; j++) {
        long long v;
        scanf("%lld", &v);
        topRow[j] = v;
        if (j == 0) {
            a00 = v;
            leftCol[0] = v;
        }
    }
    for (int i = 1; i < N; i++) {
        for (int j = 0; j < N; j++) {
            long long v;
            scanf("%lld", &v);
            if (j == 0) {
                leftCol[i] = v;
            } else {
                long long lhs = v - leftCol[i] - topRow[j] + a00;
                if (lhs != 0) {
                    printf("-1\n");
                    free(topRow);
                    free(leftCol);
                    return 0;
                }
            }
        }
    }
    long long minBaseRow = (N > 0 ? (a00 - leftCol[0]) : 0);
    long long maxBaseCol = (N > 0 ? (topRow[0] - a00) : 0);
    long long sumBaseRow = 0;
    long long sumBaseCol = 0;

    for (int i = 0; i < N; i++) {
        long long baseRow = a00 - leftCol[i];
        sumBaseRow += baseRow;
        if (baseRow < minBaseRow) minBaseRow = baseRow;
    }
    for (int j = 0; j < N; j++) {
        long long baseCol = topRow[j] - a00;
        sumBaseCol += baseCol;
        if (baseCol > maxBaseCol) maxBaseCol = baseCol;
    }
    long long x = 0;
    long long y = 0;
    if (minBaseRow < 0) x = -minBaseRow;
    if (maxBaseCol > 0) y = maxBaseCol;
    long long ans = (long long)N * x + sumBaseRow + (long long)N * y - sumBaseCol;
    printf("%lld\n", ans);
    free(topRow);
    free(leftCol);
    return 0;
}

data.statement:
A reactor core is modelled as an [[N]] × [[N]] grid of integer energy values.
To equalise the reactor, all energy values must be equal using the minimum number of operations.

One operation consists of exactly one of the following control actions:

•Choose a row index [[i]] and increase every cell in row [[i]] by {{1}}
•Choose a column index [[j]] and increase every cell in column [[j]] by {{1}}

Operations may be applied any number of times up to 100.

data.constraints:
{{1}} ≤ [[N]] ≤ {{10}}
{{0}} ≤ grid values ≤ {{100}}
The result fits in a 64‑bit signed integer.
